{
  "name": "Furia Rock Kids - Cotizador Pro",
  "description": "Herramienta avanzada de cotización para productos Furia Rock Kids, con cálculos automáticos de costos, márgenes de ganancia y asistente de ventas con IA.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'Niño' | 'Adulto';

export interface ProductReference {
  id: string;
  name: string;
  baseCostNiño: number;
  baseCostAdulto: number;
  description: string;
}

export interface QuoteInputs {
  referencia: string;
  categoria: Category;
  talla: string;
  cmEstampado: number;
  cmCorazon: number;
}

export interface QuoteResults {
  costoBase: number;
  costoEstampado: number;
  costoCorazon: number;
  costoTotal: number;
  precioSugerido: number;
  ganancia: number;
  margen: number;
}

import { ProductReference } from './types';

export const PRODUCT_REFERENCES: ProductReference[] = [
  {
    id: 'cam-basic',
    name: 'Camiseta Algodón Premium',
    baseCostNiño: 15000,
    baseCostAdulto: 22000,
    description: 'Camiseta 100% algodón, ideal para rockear.'
  },
  {
    id: 'hoodie-rock',
    name: 'Hoodie Rockero con Capucha',
    baseCostNiño: 45000,
    baseCostAdulto: 58000,
    description: 'Saco con capota abrigado y duradero.'
  },
  {
    id: 'tank-top',
    name: 'Esqueleto Rock Kids',
    baseCostNiño: 12000,
    baseCostAdulto: 18000,
    description: 'Perfecto para climas cálidos.'
  },
  {
    id: 'jacket-denim',
    name: 'Chaqueta Denim Custom',
    baseCostNiño: 65000,
    baseCostAdulto: 85000,
    description: 'Mezclilla de alta calidad lista para parches.'
  },
  {
    id: 'onesie-baby',
    name: 'Body Bebé Rockero',
    baseCostNiño: 10000,
    baseCostAdulto: 0, // No aplica
    description: 'Para los rockeros que apenas empiezan.'
  }
];

export const TALLAS_NIÑO = ['0-3m', '3-6m', '6-12m', '2', '4', '6', '8', '10', '12', '14', '16'];
export const TALLAS_ADULTO = ['S', 'M', 'L', 'XL', 'XXL'];

export const COSTO_POR_CM2 = 45; // Costo de tinta/trabajo por cm2
export const COSTO_CM2_CORAZON = 65; // Costo premium por cm2 corazón
export const MARGEN_DEFAULT = 1.6; // 60% de margen sobre el costo total

import { GoogleGenAI } from "@google/genai";
import { QuoteResults, QuoteInputs, ProductReference } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSalesAdvice = async (
  inputs: QuoteInputs,
  results: QuoteResults,
  product: ProductReference
) => {
  try {
    const prompt = `
      Actúa como un experto en ventas de ropa rockera para niños y adultos de la marca "Furia Rock Kids".

      Datos de la cotización actual:
      - Producto: ${product.name}
      - Talla: ${inputs.talla} (${inputs.categoria})
      - Precio de Venta: $${results.precioSugerido.toLocaleString()} COP
      - Área de estampado: ${inputs.cmEstampado} cm2

      Genera un breve discurso de venta (pitch) persuasivo y con estilo rockero para convencer al cliente de comprar esta prenda. Menciona la calidad y el diseño único. Máximo 3 párrafos. Usa un tono rebelde pero profesional.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.8,
      },
    });

    return response.text;
  } catch (error) {
    console.error("Error generating sales advice:", error);
    return "¡Sigue rockeando! Esta prenda es única y el precio es justo para la calidad que entregamos.";
  }
};

export type Category = 'Niño' | 'Adulto';

export interface ProductReference {
  id: string;
  name: string;
  baseCostNiño: number;
  baseCostAdulto: number;
  description: string;
}

export interface QuoteInputs {
  referencia: string;
  categoria: Category;
  talla: string;
  cmEstampado: number;
  cmCorazon: number;
}

export interface QuoteResults {
  costoBase: number;
  costoEstampado: number;
  costoCorazon: number;
  costoPlanchado: number;
  costoEmpaque: number;
  costoTotal: number;
  precioSugerido: number;
  ganancia: number;
  margen: number;
}

import { ProductReference } from './types';

export const PRODUCT_REFERENCES_INITIAL: ProductReference[] = [
  {
    id: 'cam-basic',
    name: 'Camiseta Algodón Premium',
    baseCostNiño: 15000,
    baseCostAdulto: 22000,
    description: 'Camiseta 100% algodón, ideal para rockear.'
  },
  {
    id: 'hoodie-rock',
    name: 'Hoodie Rockero con Capucha',
    baseCostNiño: 45000,
    baseCostAdulto: 58000,
    description: 'Saco con capota abrigado y duradero.'
  },
  {
    id: 'tank-top',
    name: 'Esqueleto Rock Kids',
    baseCostNiño: 12000,
    baseCostAdulto: 18000,
    description: 'Perfecto para climas cálidos.'
  },
  {
    id: 'jacket-denim',
    name: 'Chaqueta Denim Custom',
    baseCostNiño: 65000,
    baseCostAdulto: 85000,
    description: 'Mezclilla de alta calidad lista para parches.'
  },
  {
    id: 'onesie-baby',
    name: 'Body Bebé Rockero',
    baseCostNiño: 10000,
    baseCostAdulto: 0,
    description: 'Para los rockeros que apenas empiezan.'
  }
];

export const TALLAS_NIÑO = ['0-3m', '3-6m', '6-12m', '2', '4', '6', '8', '10', '12', '14', '16'];
export const TALLAS_ADULTO = ['S', 'M', 'L', 'XL', 'XXL'];

export const COSTO_POR_CM2 = 170; // Nuevo costo por cm2 ($170)
export const COSTO_PLANCHADO = 1000;
export const COSTO_EMPAQUE = 1300;
export const GANANCIA_FIJA = 30000;

import React, { useState, useMemo, useRef } from 'react';
import * as XLSX from 'xlsx';
import { QuoteInputs, QuoteResults, ProductReference } from './types';
import { 
  PRODUCT_REFERENCES_INITIAL, 
  TALLAS_NIÑO, 
  TALLAS_ADULTO, 
  COSTO_POR_CM2, 
  COSTO_PLANCHADO,
  COSTO_EMPAQUE,
  GANANCIA_FIJA
} from './constants';
import { getSalesAdvice } from './services/geminiService';
import { 
  PieChart, 
  Pie, 
  Cell, 
  ResponsiveContainer, 
  Tooltip, 
  Legend, 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid 
} from 'recharts';
import { 
  Calculator, 
  RockingChair as Rock, 
  Shirt, 
  DollarSign, 
  TrendingUp, 
  Layers, 
  Sparkles,
  Info,
  Loader2,
  FileUp,
  Package,
  Flame
} from 'lucide-react';

const App: React.FC = () => {
  const [productRefs, setProductRefs] = useState<ProductReference[]>(PRODUCT_REFERENCES_INITIAL);
  const [inputs, setInputs] = useState<QuoteInputs>({
    referencia: productRefs[0].id,
    categoria: 'Niño',
    talla: TALLAS_NIÑO[3], 
    cmEstampado: 0,
    cmCorazon: 0
  });

  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Dynamic calculations based on user requirements
  const results = useMemo((): QuoteResults => {
    const product = productRefs.find(p => p.id === inputs.referencia) || productRefs[0];
    const costoBase = inputs.categoria === 'Niño' ? product.baseCostNiño : product.baseCostAdulto;

    // Costo cm2 = $170 (both types according to latest logic)
    const costoEstampado = Number(inputs.cmEstampado || 0) * COSTO_POR_CM2;
    const costoCorazon = Number(inputs.cmCorazon || 0) * COSTO_POR_CM2;

    const costoTotal = costoBase + costoEstampado + costoCorazon + COSTO_PLANCHADO + COSTO_EMPAQUE;

    // Ganancia fija de $30.000
    const precioSugerido = Math.round(costoTotal + GANANCIA_FIJA);
    const ganancia = GANANCIA_FIJA;
    const margen = (ganancia / precioSugerido) * 100;

    return {
      costoBase,
      costoEstampado,
      costoCorazon,
      costoPlanchado: COSTO_PLANCHADO,
      costoEmpaque: COSTO_EMPAQUE,
      costoTotal,
      precioSugerido,
      ganancia,
      margen
    };
  }, [inputs, productRefs]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setInputs(prev => {
      const next = { ...prev, [name]: name.includes('cm') ? Number(value) : value };
      if (name === 'categoria') {
        next.talla = value === 'Niño' ? TALLAS_NIÑO[3] : TALLAS_ADULTO[0];
      }
      if (next.referencia === 'onesie-baby') {
        next.categoria = 'Niño';
      }
      return next;
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const data = await file.arrayBuffer();
      const wb = XLSX.read(data, { type: 'array' });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws) as any[];

      // Expected columns: id, name, baseCostNiño, baseCostAdulto, description
      const newRefs: ProductReference[] = rows.map((row, index) => ({
        id: row.id || `custom-${index}`,
        name: row.name || row.Nombre || 'Producto sin nombre',
        baseCostNiño: Number(row.baseCostNiño || row.CostoNiño || 0),
        baseCostAdulto: Number(row.baseCostAdulto || row.CostoAdulto || 0),
        description: row.description || row.Descripcion || ''
      }));

      if (newRefs.length > 0) {
        setProductRefs(newRefs);
        setInputs(prev => ({ ...prev, referencia: newRefs[0].id }));
        alert('Base de datos cargada con éxito');
      }
    } catch (err) {
      console.error(err);
      alert('Error al procesar el archivo. Asegúrate de que las columnas coincidan.');
    }
  };

  const generatePitch = async () => {
    setIsAiLoading(true);
    const product = productRefs.find(p => p.id === inputs.referencia)!;
    const advice = await getSalesAdvice(inputs, results, product);
    setAiAdvice(advice);
    setIsAiLoading(false);
  };

  const chartData = [
    { name: 'Base', value: results.costoBase, color: '#6366f1' },
    { name: 'Estampados', value: results.costoEstampado + results.costoCorazon, color: '#ec4899' },
    { name: 'Extras', value: results.costoPlanchado + results.costoEmpaque, color: '#f59e0b' },
  ];

  return (
    <div className="min-h-screen bg-slate-950 pb-20">
      <header className="bg-slate-900 border-b border-red-900/50 py-6 px-4 md:px-8 mb-8 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-red-600 p-2 rounded-lg rotate-3 shadow-[0_0_15px_rgba(220,38,38,0.5)]">
              <Shirt size={32} className="text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tighter text-white">FURIA <span className="text-red-600">ROCK</span> KIDS</h1>
              <p className="text-xs text-slate-400 uppercase tracking-widest font-semibold">Cotizador con Ganancia Fija</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 text-sm font-bold px-4 py-2 rounded-xl transition-all border border-slate-700"
            >
              <FileUp size={16} />
              Cargar Base (XLSX)
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              accept=".xlsx,.xls,.csv" 
              className="hidden" 
            />
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 md:px-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-slate-900 rounded-3xl p-6 border border-slate-800 shadow-xl">
            <div className="flex items-center gap-2 mb-6">
              <Calculator className="text-red-500" />
              <h2 className="text-xl font-bold text-white">Configurar Cotización</h2>
            </div>

            <div className="space-y-5">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Referencia</label>
                <select 
                  name="referencia"
                  value={inputs.referencia}
                  onChange={handleInputChange}
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-500 focus:outline-none transition-all"
                >
                  {productRefs.map(ref => (
                    <option key={ref.id} value={ref.id}>{ref.name}</option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-400 mb-2">Categoría</label>
                  <select 
                    name="categoria"
                    disabled={inputs.referencia === 'onesie-baby'}
                    value={inputs.categoria}
                    onChange={handleInputChange}
                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-500 focus:outline-none transition-all disabled:opacity-50"
                  >
                    <option value="Niño">Niño</option>
                    <option value="Adulto">Adulto</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-400 mb-2">Talla</label>
                  <select 
                    name="talla"
                    value={inputs.talla}
                    onChange={handleInputChange}
                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-500 focus:outline-none transition-all"
                  >
                    {(inputs.categoria === 'Niño' ? TALLAS_NIÑO : TALLAS_ADULTO).map(talla => (
                      <option key={talla} value={talla}>{talla}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-400 mb-2">Cm² Principal ($170)</label>
                  <div className="relative">
                    <input 
                      type="number"
                      name="cmEstampado"
                      value={inputs.cmEstampado}
                      onChange={handleInputChange}
                      className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 pl-10 text-white focus:ring-2 focus:ring-red-500 focus:outline-none"
                    />
                    <Layers className="absolute left-3 top-3.5 text-slate-500" size={18} />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-400 mb-2">Cm² Corazón ($170)</label>
                  <div className="relative">
                    <input 
                      type="number"
                      name="cmCorazon"
                      value={inputs.cmCorazon}
                      onChange={handleInputChange}
                      className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 pl-10 text-white focus:ring-2 focus:ring-red-500 focus:outline-none"
                    />
                    <Sparkles className="absolute left-3 top-3.5 text-slate-500" size={18} />
                  </div>
                </div>
              </div>
            </div>
          </section>

          <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800">
            <h4 className="text-white font-bold mb-4 flex items-center gap-2">
              <Package size={18} className="text-blue-500" />
              Detalle de Gastos Fijos
            </h4>
            <div className="space-y-3">
              <div className="flex justify-between items-center bg-slate-800/50 p-3 rounded-xl">
                <span className="text-slate-400 text-sm">Planchado</span>
                <span className="text-white font-bold">${COSTO_PLANCHADO.toLocaleString()}</span>
              </div>
              <div className="flex justify-between items-center bg-slate-800/50 p-3 rounded-xl">
                <span className="text-slate-400 text-sm">Empaque</span>
                <span className="text-white font-bold">${COSTO_EMPAQUE.toLocaleString()}</span>
              </div>
              <div className="flex justify-between items-center bg-green-900/20 p-3 rounded-xl border border-green-900/30">
                <span className="text-green-400 text-sm font-bold">GANANCIA FIJA</span>
                <span className="text-green-400 font-bold">${GANANCIA_FIJA.toLocaleString()}</span>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-7 space-y-8">
          <div className="relative overflow-hidden bg-gradient-to-br from-red-600 to-red-900 rounded-[2.5rem] p-8 shadow-2xl">
            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div className="text-center md:text-left">
                <h3 className="text-white/80 font-bold uppercase tracking-widest text-sm mb-1">Precio Final</h3>
                <div className="flex items-baseline gap-2 justify-center md:justify-start">
                  <span className="text-6xl font-black text-white tracking-tighter">${results.precioSugerido.toLocaleString()}</span>
                  <span className="text-xl text-white/70 font-bold">COP</span>
                </div>
                <div className="mt-4 inline-flex items-center gap-2 bg-black/20 backdrop-blur-md px-5 py-2 rounded-full text-white text-sm font-bold border border-white/10">
                  <Flame size={16} className="text-orange-400" />
                  Margen: {results.margen.toFixed(2)}%
                </div>
              </div>
              <div className="bg-black/30 p-6 rounded-3xl backdrop-blur-xl border border-white/10 w-full md:w-64">
                <p className="text-white/60 text-xs font-bold uppercase mb-3">Resumen Costos</p>
                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-white/70">Base:</span>
                    <span className="text-white font-bold">${results.costoBase.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-white/70">Estampados:</span>
                    <span className="text-white font-bold">${(results.costoEstampado + results.costoCorazon).toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-white/70">Fijos:</span>
                    <span className="text-white font-bold">${(results.costoPlanchado + results.costoEmpaque).toLocaleString()}</span>
                  </div>
                  <div className="pt-2 mt-2 border-t border-white/20 flex justify-between font-black text-white">
                    <span>COSTO TOTAL:</span>
                    <span>${results.costoTotal.toLocaleString()}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800">
              <h4 className="text-white font-bold mb-6 flex items-center gap-2">
                <Layers size={18} className="text-indigo-500" />
                Desglose Costos
              </h4>
              <div className="h-48">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie data={chartData} innerRadius={40} outerRadius={60} paddingAngle={5} dataKey="value">
                      {chartData.map((entry, index) => <Cell key={index} fill={entry.color} />)}
                    </Pie>
                    <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', color: '#fff' }} />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 flex flex-col justify-center text-center">
              <p className="text-slate-400 text-sm uppercase font-bold tracking-widest mb-1">Ganancia por Prenda</p>
              <p className="text-4xl font-black text-green-400">${GANANCIA_FIJA.toLocaleString()}</p>
              <div className="mt-4 bg-green-500/10 py-2 rounded-xl border border-green-500/20">
                <p className="text-green-500 text-xs font-bold">ESTABILIDAD FINANCIERA ACTIVA</p>
              </div>
            </div>
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6 relative overflow-hidden group">
             <div className="flex items-center justify-between mb-4 relative z-10">
                <div className="flex items-center gap-3">
                  <div className="bg-indigo-600/20 p-2 rounded-xl">
                    <Sparkles className="text-indigo-500" size={24} />
                  </div>
                  <div>
                    <h4 className="text-white font-bold">Generador de Pitch (IA)</h4>
                    <p className="text-xs text-slate-400">Argumento persuasivo basado en precio actual</p>
                  </div>
                </div>
                <button 
                  onClick={generatePitch}
                  disabled={isAiLoading}
                  className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white font-bold px-6 py-2.5 rounded-xl transition-all shadow-lg flex items-center gap-2"
                >
                  {isAiLoading ? <Loader2 className="animate-spin" size={20} /> : 'Generar'}
                </button>
             </div>
             <div className="min-h-[100px] bg-slate-950/50 rounded-2xl p-6 border border-slate-800/50 relative z-10 italic text-slate-300">
                {aiAdvice || "Haz clic en generar para obtener un discurso de ventas profesional."}
             </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/80 backdrop-blur-md border-t border-slate-800 py-3 px-8 z-50">
        <div className="max-w-7xl mx-auto flex justify-between items-center text-xs font-bold text-slate-400">
          <div className="flex gap-4">
             <span>TINTA: ${COSTO_POR_CM2}/cm²</span>
             <span>PLANCHADO: ${COSTO_PLANCHADO}</span>
             <span>EMPAQUE: ${COSTO_EMPAQUE}</span>
          </div>
          <div className="text-green-500 uppercase">Furia Rock Kids • 2024 Cotizador Pro</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

{
  "name": "Furia Rock Kids - Cotizador Pro",
  "description": "Herramienta avanzada de cotización para productos Furia Rock Kids, con cálculos automáticos de costos ($170/cm2), ganancia fija de $30k y asistente de ventas con IA.",
  "requestFramePermissions": []
}

