Requiere SheetJS. Si ya lo estás usando, perfecto. Si no, al final te digo cómo importarlo.

// ====== CONFIG COSTOS ======
const COSTO_CM2 = 170;
const COSTO_PLANCHADO = 1000;
const COSTO_EMPAQUE = 1300;
const GANANCIA_FIJA = 30000;

// ====== ESTADO EN MEMORIA ======
let productos = [];                 // filas completas del excel
let productoPorRef = new Map();     // referencia -> fila
let referenciaSeleccionada = null;

// ====== HELPERS ======
function normalizarHeader(h) {
  return String(h || "")
    .trim()
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // quita tildes
    .replace(/\s+/g, "_");
}

function findKey(obj, posibles) {
  const keys = Object.keys(obj);
  for (const p of posibles) {
    const hit = keys.find(k => normalizarHeader(k) === normalizarHeader(p));
    if (hit) return hit;
  }
  return null;
}

function money(n) {
  return Math.round(Number(n || 0));
}

// ====== ELEMENTOS UI ======
const fileBase = document.getElementById("fileBase");
const btnCargarBase = document.getElementById("btnCargarBase");
const selReferencia = document.getElementById("selReferencia");
const inpPrecioUnitario = document.getElementById("inpPrecioUnitario");
const inpPlanchadosQty = document.getElementById("inpPlanchadosQty");

// (si tienes inputs de cm2)
const inpCm2Principal = document.getElementById("inpCm2Principal"); // opcional
const inpCm2Corazon = document.getElementById("inpCm2Corazon");     // opcional

btnCargarBase.addEventListener("click", () => fileBase.click());

// ====== CARGA DE XLSX ======
fileBase.addEventListener("change", async (e) => {
  const file = e.target.files?.[0];
  if (!file) return;

  try {
    const data = await file.arrayBuffer();
    const wb = XLSX.read(data, { type: "array" });

    // Usa la primera hoja (o cambia el nombre si lo necesitas)
    const ws = wb.Sheets[wb.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(ws, { defval: "" });

    if (!rows.length) {
      alert("El archivo no tiene filas.");
      return;
    }

    // Detecta columnas
    const refKey = findKey(rows[0], ["referencia", "ref", "reference"]);
    const precioKey = findKey(rows[0], [
      "precio_unitario",
      "precio unitario",
      "precio",
      "costo_unitario",
      "costo unitario",
      "unit_price",
      "unitprice"
    ]);

    if (!refKey) {
      alert("No encontré la columna 'referencia' en tu archivo.");
      return;
    }
    if (!precioKey) {
      alert("No encontré la columna de 'precio unitario' (ej: precio_unitario / precio unitario / precio).");
      return;
    }

    // Limpia y crea mapa referencia -> fila
    productos = rows
      .map(r => ({
        ...r,
        __ref: String(r[refKey]).trim(),
        __precio: Number(String(r[precioKey]).toString().replace(/[^\d.]/g, "")) || 0,
      }))
      .filter(r => r.__ref);

    productoPorRef = new Map(productos.map(p => [p.__ref, p]));

    // Pinta el select
    selReferencia.innerHTML = "";
    const opt0 = document.createElement("option");
    opt0.value = "";
    opt0.textContent = "Selecciona una referencia...";
    selReferencia.appendChild(opt0);

    [...productoPorRef.keys()].sort().forEach(ref => {
      const opt = document.createElement("option");
      opt.value = ref;
      opt.textContent = ref;
      selReferencia.appendChild(opt);
    });

    alert(`Base cargada ✅ (${productos.length} productos)`);

  } catch (err) {
    console.error(err);
    alert("Error leyendo el archivo. Verifica que sea XLSX válido.");
  } finally {
    fileBase.value = ""; // permite cargar el mismo archivo otra vez
  }
});

// ====== AL CAMBIAR REFERENCIA → CARGA PRECIO UNITARIO ======
selReferencia.addEventListener("change", () => {
  const ref = selReferencia.value;
  referenciaSeleccionada = ref || null;

  if (!ref) {
    inpPrecioUnitario.value = "";
    recalcular(); // si tienes cálculo
    return;
  }

  const prod = productoPorRef.get(ref);
  if (!prod) {
    inpPrecioUnitario.value = "";
    recalcular();
    return;
  }

  inpPrecioUnitario.value = money(prod.__precio);
  recalcular();
});

// ====== PLANCHADOS: CAMBIA CANTIDAD Y RECALCULA ======
inpPlanchadosQty.addEventListener("input", recalcular);
if (inpCm2Principal) inpCm2Principal.addEventListener("input", recalcular);
if (inpCm2Corazon) inpCm2Corazon.addEventListener("input", recalcular);

// ====== TU CÁLCULO CENTRAL ======
function recalcular() {
  const basePrenda = Number(inpPrecioUnitario.value || 0);

  const cm2Principal = Number(inpCm2Principal?.value || 0);
  const cm2Corazon = Number(inpCm2Corazon?.value || 0);

  const qtyPlanchados = Math.max(0, parseInt(inpPlanchadosQty.value || "0", 10));

  const estampado = cm2Principal * COSTO_CM2;
  const corazon = cm2Corazon * COSTO_CM2;

  const costoPlanchado = qtyPlanchados * COSTO_PLANCHADO;

  const costoTotal =
    basePrenda +
    estampado +
    corazon +
    costoPlanchado +
    COSTO_EMPAQUE;

  const precioVenta = costoTotal + GANANCIA_FIJA;

  // Aquí actualizas tu UI (ids de ejemplo)
  const elCostoTotal = document.getElementById("txtCostoTotal");
  const elPrecioVenta = document.getElementById("txtPrecioVenta");
  const elGanancia = document.getElementById("txtGanancia");

  if (elCostoTotal) elCostoTotal.textContent = money(costoTotal).toLocaleString("es-CO");
  if (elPrecioVenta) elPrecioVenta.textContent = money(precioVenta).toLocaleString("es-CO");
  if (elGanancia) elGanancia.textContent = money(GANANCIA_FIJA).toLocaleString("es-CO");
}

