const TALLAS_ADULTO = ["S", "M", "L", "XL"];
const TALLAS_NINO = ["2", "4", "6", "8", "10", "12", "14", "16"];

const selCategoria = document.getElementById("selCategoria");
const selTalla = document.getElementById("selTalla");

function setOptions(selectEl, options, placeholder = "Selecciona...") {
  selectEl.innerHTML = "";
  const opt0 = document.createElement("option");
  opt0.value = "";
  opt0.textContent = placeholder;
  selectEl.appendChild(opt0);

  options.forEach(v => {
    const opt = document.createElement("option");
    opt.value = v;
    opt.textContent = v;
    selectEl.appendChild(opt);
  });
}

function actualizarTallasPorCategoria() {
  const cat = (selCategoria.value || "").toLowerCase();

  if (cat === "niño" || cat === "nino") {
    setOptions(selTalla, TALLAS_NINO, "Talla niño...");
  } else {
    setOptions(selTalla, TALLAS_ADULTO, "Talla adulto...");
  }

  // opcional: resetear selección si cambia categoría
  selTalla.value = "";
}

selCategoria.addEventListener("change", () => {
  actualizarTallasPorCategoria();
  recalcular?.();
});

// Llama una vez al cargar la página
actualizarTallasPorCategoria();

