             <div className="min-h-[140px] bg-slate-950/80 rounded-3xl p-10 border border-slate-800/50 text-slate-300 leading-relaxed font-semibold italic text-lg">
                {aiAdvice ? `"${aiAdvice}"` : "Configura la cotización y obtén un discurso de ventas profesional."}
             </div>
