    doc.text('COTIZACIÓN', 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.text('FURIA ROCK KIDS - ROPA CON ACTITUD', 105, 30, { align: 'center' });

    // Client/Order Data
