    baseCost: 45000,
    description: 'Saco con capota.'
  }
];

export const TALLAS_NINO = ['2', '4', '6', '8', '10', '12', '14', '16'];
export const TALLAS_ADULTO = ['S', 'M', 'L', 'XL', 'XXL'];

export const COLORES_PRENDA = [
  "Blanco",
  "Negro",
  "Arena",
