  <label>Color Bermuda / Jogger</label>
  <div id="paletaBermuda" class="paleta"></div>
</div>

✅ 3. CSS – Botones bonitos (IMPORTANTE para Google Studio)
.paleta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 6px;
}

.color-btn {
  padding: 6px 10px;
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,0.15);
  background: rgba(255,255,255,0.05);
  cursor: pointer;
  font-size: 12px;
  color: white;
  transition: 0.2s;
}

.color-btn:hover {
  background: rgba(255,255,255,0.12);
  transform: translateY(-1px);
}

.color-btn.active {
  border: 2px solid #00E0FF;
  background: rgba(0,224,255,0.15);
}

✅ 4. JS – Construir paletas automáticamente
let colorCamiseta = null;
let colorBermuda = null;

function crearPaleta(containerId, colores, onSelect) {
  const container = document.getElementById(containerId);
  container.innerHTML = "";

  colores.forEach(color => {
    const btn = document.createElement("div");
    btn.className = "color-btn";
    btn.textContent = color;

    btn.onclick = () => {
      [...container.children].forEach(c => c.classList.remove("active"));
      btn.classList.add("active");
      onSelect(color);
      recalcular?.();
    };

    container.appendChild(btn);
  });
}

crearPaleta("paletaCamiseta", COLORES_CAMISETA, (color) => {
  colorCamiseta = color;
});

crearPaleta("paletaBermuda", COLORES_BERMUDA, (color) => {
  colorBermuda = color;
});

✅ 5. Cómo usar los colores en tu cotizador

Cuando generes PDF / pedido / resumen:

console.log("Color camiseta:", colorCamiseta);
console.log("Color bermuda:", colorBermuda);


o en el documento:

const pedido = {
  referencia: selReferencia.value,
  talla: selTalla.value,
  colorCamiseta,
  colorBermuda,
  precio: precioVenta
};

✅ Por qué esta solución es MEJOR que imágenes

✔ No dependes de fotos
✔ No hay errores de carga
✔ No pesa nada
✔ Escalable (agregas colores en 1 línea)
✔ Funciona perfecto en Google Studio / Apps Script / Vercel / React

Y visualmente queda tipo Nike / Adidas configurador.

