    if (name === "observaciones") {
      setObservaciones(value);
      return;
    }
    setInputs(prev => ({ 
      ...prev, 
      [name]: (name.includes('cm') || name.includes('qty') || name === 'quantity' || name === 'costoEmpaque') ? Number(value) : value 
