    doc.text(splitObs, 15, finalY + 75);

    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.text('Este documento tiene validez por 15 días.', 105, 285, { align: 'center' });

    doc.save(`Cotizacion_FuriaRockKids_${inputs.clientName || 'Cliente'}.pdf`);
  };

