                  </div>
                </div>
                <button onClick={generatePitch} disabled={isAiLoading} className="bg-indigo-600 hover:bg-indigo-500 text-white font-black px-10 py-4 rounded-2xl transition-all flex items-center justify-center gap-3 uppercase text-xs tracking-widest shadow-lg active:scale-95 disabled:opacity-50">
                  {isAiLoading ? <Loader2 className="animate-spin" size={20} /> : 'Generar Pitch'}
                </button>
             </div>
             <div className="min-h-[140px] bg-slate-950/80 rounded-3xl p-10 border border-slate-800/50 text-slate-300 leading-relaxed font-semibold italic text-lg shadow-inner">
                {aiAdvice ? `"${aiAdvice}"` : "Configura el pedido y haz clic en 'Generar Pitch' para obtener un discurso de ventas profesional."}
             </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur-2xl border-t border-slate-800 py-5 px-10 z-50">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6 text-[10px] font-black uppercase tracking-[0.3em] text-slate-500">
          <div className="flex flex-wrap justify-center gap-8 font-bold">
             <span className="flex items-center gap-3"><div className="w-2.5 h-2.5 rounded-full bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.5)]"></div> TINTA: ${COSTO_CM2}/cm²</span>
             <span className="flex items-center gap-3"><div className="w-2.5 h-2.5 rounded-full bg-indigo-600 shadow-[0_0_8px_rgba(79,70,229,0.5)]"></div> PLANCHADO: ${COSTO_PLANCHADO} / unidad</span>
             <span className="flex items-center gap-3"><div className="w-2.5 h-2.5 rounded-full bg-emerald-600 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div> EMPAQUE: VARIABLE</span>
          </div>
          <div className="text-indigo-400 font-black tracking-widest">FURIA ROCK KIDS • OPERATIONAL SYSTEMS</div>
        </div>
      </footer>
    </div>
  );
};

export default App;
